import json

history_data = locals()['var_function-call-5322302462408338770']
case_data = locals()['var_function-call-7353216773410307250']

def clean_id(i):
    if not i: return None
    i = str(i).strip()
    if i.startswith('#'): i = i[1:]
    return i

# Identify all agents who handled cases
# Agents who are current owners or appeared in history
agents_handled = set()
for r in case_data:
    oid = clean_id(r.get('ownerid'))
    if oid and oid.startswith('005'):
        agents_handled.add(oid)

for r in history_data:
    nv = clean_id(r.get('newvalue__c'))
    ov = clean_id(r.get('oldvalue__c'))
    if nv and nv.startswith('005'):
        agents_handled.add(nv)
    if ov and ov.startswith('005'):
        agents_handled.add(ov)

# Calculate Transfer Counts (Outgoing) in the period
# History data is already filtered by date
transfer_counts = {a: 0 for a in agents_handled}
handled_counts_period = {a: 0 for a in agents_handled} # Just for tie breaking interest

for r in history_data:
    ov = clean_id(r.get('oldvalue__c'))
    nv = clean_id(r.get('newvalue__c'))

    # Outgoing transfer
    if ov and ov.startswith('005'):
        if ov in transfer_counts:
            transfer_counts[ov] += 1

    # Incoming/Initial (Handled event in period)
    if nv and nv.startswith('005'):
        if nv in handled_counts_period:
            handled_counts_period[nv] += 1

# Filter: Handled > 0 cases
# As defined, all in agents_handled have handled at least one case (either current or in history)
candidates = []
for a in agents_handled:
    candidates.append({
        'id': a,
        'transfers': transfer_counts[a],
        'handled_period': handled_counts_period[a]
    })

# Sort by transfers (asc), then handled_period (desc)
candidates.sort(key=lambda x: (x['transfers'], -x['handled_period']))

print("__RESULT__:")
print(json.dumps(candidates))

